"""
MKT Original Commentary — 1 Chronicles chapter 29
Run: python3 scripts/zc-original-1chronicles-29-29.py

Key translation decisions:
- bîrāh (v1) = Persian loanword for citadel/palace — post-exilic vocabulary marker
- hitnaddᵉḇû (v6,9) = reflexive: gave voluntarily/offered willingly — key verb of the passage
- ʾădarkōnîm (v7) = darics, Persian gold coins — anachronistic if referring to David's time; post-exilic
- yēṣer (v18) = inclination/impulse of the heart — same root as Gen 6:5 (evil inclination)
- kissēʾ YHWH (v23) = throne of the LORD — the Davidic throne identified as YHWH's own throne
- lēḇāḇ šālēm (v9,19) = whole/undivided heart — Chronicler's signature covenantal phrase
- gērîm wᵉtôšāḇîm (v15) = strangers and sojourners — resident-alien status language (Ps 39:12)
- The doxology in v11 becomes the base text for the Lord's Prayer doxology (Matt 6:13 LXX tradition)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRON1 = {
  "29": {
    "1": "<p><strong>gāḏôl hammelāʾḵāh</strong> — &lsquo;the work is great.&rsquo; <strong>bîrāh</strong> — a Persian loanword meaning citadel or palace-temple complex (also Esth 1:2; Neh 1:1; Dan 8:2). Its use here is a clear marker of the Chronicler&rsquo;s post-exilic Persian-period context, even in a speech attributed to David. <strong>lōʾ lᵉʾāḏām kî laYHWH</strong> — &lsquo;not for man but for the LORD.&rsquo; The distinction between human and divine construction projects is the chapter&rsquo;s opening frame. <strong>bāḥar bô ʾĕlōhîm</strong> — &lsquo;God has chosen him&rsquo; — divine election language applied to Solomon&rsquo;s role, echoing David&rsquo;s own election vocabulary.</p>",
    "2": "<p><strong>bᵉḵol-kōḥî</strong> — &lsquo;with all my strength.&rsquo; The inventory of materials demonstrates David&rsquo;s comprehensive preparation: gold for gold work, silver for silver, bronze, iron, wood, onyx, antimony (or inlaid stones, <em>pûḵ</em> = black antimony used as eye-paint, here as mortar for colored stone inlay), colored stones, alabaster (<em>šeš</em>), and all kinds of precious stones. The MKT renders <em>ʾaḇnê-šōham</em> as &lsquo;onyx stones&rsquo; — onyx was used in the priestly ephod (Exod 28:9). The comprehensive list mirrors the Exodus tabernacle materials list (Exod 25:3-7), framing the temple as the new tabernacle.</p>",
    "3": "<p><strong>bᵉrāṣôtî bêt ʾĕlōhay</strong> — &lsquo;because of my devotion to the house of my God.&rsquo; <em>rāṣāh</em> (pleasure, delight, acceptance) used for human motivation is relatively rare; usually it describes God&rsquo;s acceptance of an offering. David&rsquo;s word for his motivation — delight in / devotion to the house of God — is the language of acceptable sacrifice applied to a personal disposition. <strong>sᵉgullātî</strong> — &lsquo;my personal treasure&rsquo; (from <em>sᵉgullāh</em>, used of Israel as God&rsquo;s treasured possession in Exod 19:5; Deut 7:6). David gives from his <em>sᵉgullāh</em> to YHWH, whose own people are his <em>sᵉgullāh</em> — a deliberate lexical echo.</p>",
    "4": "<p>The specific quantities: 3,000 talents of Ophir gold (approximately 100 metric tons) and 7,000 talents of refined silver (<em>kāsep̄ zākûḵ</em> — purified silver) — totaling extraordinary wealth. <strong>Ôp̄îr</strong> (Ophir) gold was the finest grade available in the ancient world; the Chronicler uses it as a marker of absolute quality. The quantities are hyperbolic but rhetorical — communicating the Chronicler&rsquo;s theology that David prepared the temple with incomparable dedication.</p>",
    "5": "<p><strong>limlōʾ hayyāḏayim laYHWH hayyôm</strong> — &lsquo;to fill the hands today to the LORD.&rsquo; <em>millēʾ yāḏ</em> (fill the hand) is the technical term for priestly ordination/consecration (Exod 28:41; 29:9; Lev 8:33). David invites the assembly to consecrate themselves through giving — treating the freewill offering as an act of priestly self-dedication. This sacralizing of generosity is the chapter&rsquo;s distinctive theological move.</p>",
    "6": "<p><strong>wayyitnaddᵉḇû</strong> — the reflexive Hitpael of <em>nāḏaḇ</em> (to give voluntarily, offer freely). This verb and its cognate noun (<em>nᵉḏāḇāh</em> = freewill offering) will govern the passage through v. 9. The <em>hitnaddēḇ</em> form is stronger than simple giving — it describes the moral movement of the will toward generous giving. The leaders, princes, tribal commanders, and officers all participate: the entire power structure of Israel is aligned in voluntary generosity.</p>",
    "7": "<p><strong>ʾădarkōnîm</strong> — gold darics, Persian coins minted under Darius I (522-486 BCE). These are anachronistic in a Davidic context; their mention is the most explicit post-exilic marker in the entire Davidic narrative. The Chronicler either uses the contemporary monetary unit for intelligibility, or this passage was composed entirely by post-exilic editors. The total given by the assembly: 5,000 talents of gold + 10,000 darics + 10,000 talents of silver + 18,000 talents of bronze + 100,000 talents of iron — staggering quantities emphasizing the all-Israel investment in the temple.</p>",
    "8": "<p>Precious stones are entrusted to Jehiel the Gershonite (<em>haggēršunnî</em>) for the treasury of the house of the LORD. The Gershonite Levites were responsible for transporting the tabernacle coverings (Num 4:22-28). Jehiel&rsquo;s priestly oversight of the temple treasury connects the new institution to its wilderness antecedent.</p>",
    "9": "<p><strong>wayyiśmᵉḥû hāʿām ʿal-hitnaddᵉḇām kî bᵉlēḇāḇ šālēm hitnaddᵉḇû laYHWH</strong> — &lsquo;the people rejoiced because they had given willingly, for with an undivided heart (<em>lēḇāḇ šālēm</em>) they had given willingly to the LORD.&rsquo; The repetition of <em>hitnaddēḇ</em> and the phrase <em>lēḇāḇ šālēm</em> (whole heart) make this verse the theological summit of the offering narrative. <em>Lēḇāḇ šālēm</em> (also 12:38; 28:9; 2 Chr 15:17; 16:9) is the Chronicler&rsquo;s signature requirement for proper worship: not external compliance but undivided inner orientation toward YHWH. David himself shares the rejoicing: <em>gam dāwid hammelek śāmaḥ śimḥāh gᵉḏôlāh</em>.</p>",
    "10": "<p>David&rsquo;s prayer begins with the classic Jewish berakah formula: <strong>bārûḵ ʾattāh YHWH ʾĕlōhê yiśrāʾēl ʾāḇînû mēʿôlām wᵉʿaḏ-ʿôlām</strong> — &lsquo;Blessed are you, LORD, God of Israel our father, from everlasting to everlasting.&rsquo; The formula <em>bārûḵ ʾattāh</em> is the opening of synagogue blessings and shapes the NT Lord&rsquo;s Prayer structure. The unusual phrase <em>yiśrāʾēl ʾāḇînû</em> (&lsquo;Israel our father&rsquo; — referring to the patriarch Jacob/Israel) is unique; usually the phrase is &lsquo;our fathers&rsquo; or &lsquo;Abraham, Isaac, and Jacob.&rsquo;</p>",
    "11": "<p>The great doxology: <strong>lᵉḵā YHWH haggᵉḏûllāh wᵉhaggᵉḇûrāh wᵉhattipʾāret wᵉhanneṣaḥ wᵉhahôḏ kî-ḵōl baššāmayim ûḇāʾāreṣ lᵉḵā YHWH hammamlāḵāh</strong> — &lsquo;Yours, LORD, is the greatness and the power and the glory and the victory and the majesty — for everything in the heavens and on earth is yours. Yours, LORD, is the kingdom.&rsquo; Five divine attributes are enumerated: <em>gᵉḏûllāh</em> (greatness), <em>gᵉḇûrāh</em> (power/might), <em>tīpʾāret</em> (glory/beauty/splendor), <em>neṣaḥ</em> (victory/perpetuity — can mean either), <em>hôḏ</em> (majesty/honor). This list became the basis for the doxology appended to the Lord&rsquo;s Prayer in the majority textual tradition: &lsquo;For yours is the kingdom and the power and the glory forever.&rsquo;</p>",
    "12": "<p><strong>hāʿōšer wᵉhaḵḵāḇôḏ milpānêḵā</strong> — &lsquo;riches and honor come from before you.&rsquo; Wealth and status originate in divine gift, not human achievement. <strong>ûḇᵉyāḏᵉḵā lᵉgaddēl ûlᵉḥazzēq lakkōl</strong> — &lsquo;and in your hand is to make great and to give strength to all.&rsquo; The double <em>bᵉyāḏᵉḵā</em> (in your hand) in vv. 12-16 frames the entire offering as a return of what was never ours to begin with.</p>",
    "13": "<p><strong>wᵉʿattāh ʾĕlōhênû môḏîm ʾănaḥnû lāḵ ûmᵉhallᵉlîm lᵉšēm tip̄ʾartᵉḵā</strong> — &lsquo;now therefore our God we give thanks to you and praise your glorious name.&rsquo; The transition from doxology (vv. 10-12) to thanksgiving is marked by <em>wᵉʿattāh</em> (and now / now therefore). <em>tip̄ʾartᵉḵā</em> (your glory/beauty) echoes <em>tīpʾāret</em> from v. 11 — the praise is of the very quality David has just ascribed to YHWH.</p>",
    "14": "<p><strong>kî-mî ʾănî ûmî ʿammî kî-naʿṣôr kōaḥ lᵉhitnaddēḇ kāzōʾt</strong> — &lsquo;for who am I and who are my people that we should have the ability to give willingly like this?&rsquo; The rhetorical <em>mî ʾănî</em> (who am I?) echoes Moses (Exod 3:11), Gideon (Judg 6:15), and David himself (2 Sam 7:18/1 Chr 17:16). <strong>kî-mimmᵉḵā hakkōl ûmiyyāḏᵉḵā nātannû lāḵ</strong> — &lsquo;for all things come from you, and of your own we have given you.&rsquo; This is the most concentrated statement of the theology of giving in the OT: generosity toward God consists of returning to him what already originates in him. Nothing humans offer adds to divine wealth.</p>",
    "15": "<p><strong>gērîm wᵉtôšāḇîm ʾănaḥnû lᵉp̄ānêḵā</strong> — &lsquo;we are strangers and sojourners before you.&rsquo; The paired terms <em>gēr</em> (alien resident) and <em>tôšāḇ</em> (temporary settler) are the two legal categories for non-citizens in Israel (cf. Lev 25:23 where YHWH says &lsquo;the land is mine, for you are strangers and sojourners with me&rsquo;). Ps 39:12 uses the same two terms. <strong>kᵉḵol-ʾăḇōtênû</strong> — &lsquo;as all our fathers were.&rsquo; <strong>kᵉṣel yāmênû ʿal-hāʾāreṣ wᵉʾên miqweh</strong> — &lsquo;our days on earth are as a shadow and there is no abiding.&rsquo; The shadow metaphor for human transience (also Job 8:9; Ps 102:11; Eccl 8:13) undercuts any claim to permanent ownership of property or status.</p>",
    "16": "<p><strong>YHWH ʾĕlōhênû kōl hehāmôn hazzeh ʾăšer hăḵînōnû liḇnôt-lᵉḵā bêt lᵉšēm qāḏšᵉḵā miyyāḏᵉḵā hîʾ ûlᵉḵā hakkōl</strong> — &lsquo;O LORD our God, all this abundance we have prepared to build you a house for your holy name — it is from your hand, and all of it is yours.&rsquo; The logical structure: the materials come from God (v. 14); the builders are transient sojourners (v. 15); therefore the house is God&rsquo;s own work built for God&rsquo;s own name from God&rsquo;s own resources through God&rsquo;s own stewards. Human agency is real but entirely derivative.</p>",
    "17": "<p><strong>wᵉyōḏaʿtî ʾĕlōhay kî-ʾattāh bōḥēn lēḇāḇ ûmêšārîm tirṣeh</strong> — &lsquo;and I know, my God, that you test the heart and delight in uprightness.&rsquo; <em>bōḥēn lēḇāḇ</em> (test/examine the heart) is an important divine attribute (Ps 7:9; Prov 17:3; Jer 11:20; 17:10) — God&rsquo;s knowledge goes beyond the observable to the inner motivation. <em>mêšārîm</em> (uprightness/integrity, from <em>yāšar</em> = straight) — the quality YHWH delights in. <strong>ʾănî bᵉyōšer lᵉḇāḇî hitnaddaḇtî kol-ʾēlleh</strong> — &lsquo;with the uprightness of my heart I have offered willingly all these things.&rsquo; David models the integration of external giving with internal integrity — the two cannot be separated.</p>",
    "18": "<p><strong>šᵉmōr-zōʾt lᵉʿôlām lᵉyēṣer maḥšᵉḇôt lᵉḇaḇ ʿammᵉḵā</strong> — &lsquo;keep this disposition forever in the inclinations of the thoughts of the heart of your people.&rsquo; <em>yēṣer</em> (inclination/impulse) is the term used in Gen 6:5 for the &lsquo;evil inclination&rsquo; (<em>yēṣer libbô raq raʿ kol-hayyôm</em>). Here the <em>yēṣer</em> is the just-expressed disposition of generous whole-heartedness. David prays that the good <em>yēṣer</em> he has just witnessed in the assembly will be sustained by divine action — recognizing that even the inclination to give rightly is a gift requiring divine preservation.</p>",
    "19": "<p><strong>ûlišlōmōh bᵉnî tēn lēḇāḇ šālēm</strong> — &lsquo;and give to my son Solomon an undivided heart.&rsquo; David&rsquo;s specific petition for Solomon focuses on <em>lēḇāḇ šālēm</em> — the whole/undivided heart that is the Chronicler&rsquo;s hallmark of faithful covenant relationship. The threefold object: &lsquo;to keep your commandments, your testimonies, and your statutes&rsquo; (<em>miṣwōtêḵā ʿēḏôtêḵā wᵉḥuqqêḵā</em>) is the standard Deuteronomic covenant-obedience formula (Deut 6:17; 1 Kgs 2:3). <em>habbîrāh</em> (the citadel/palace-temple) closes the verse, forming a ring with v. 1&rsquo;s <em>bîrāh</em> — the whole chapter has the temple project as its frame.</p>",
    "20": "<p>David calls the assembly to bless (<em>bārᵉḵû</em>) the LORD. The response: <strong>wayyiqqᵉḏû wayyištaḥăwû laYHWH wᵉlammeleḵ</strong> — &lsquo;they bowed down and worshipped the LORD and the king.&rsquo; The double object of prostration — YHWH and the king — reflects the Chronicler&rsquo;s theology of the Davidic king as YHWH&rsquo;s vice-regent. The worship of the king is not idolatry but the recognition of divinely established authority (cf. Ps 45:11 where the bride is told to worship the king).</p>",
    "21": "<p>The assembly&rsquo;s sacrifices: a thousand bulls, a thousand rams, a thousand lambs, with their drink offerings. <strong>ûzᵉḇāḥîm lārōḇ lᵉḵol-yiśrāʾēl</strong> — &lsquo;and sacrifices in abundance for all Israel.&rsquo; The triple thousand (three kinds of animals) is a round number of completeness. The drink offerings (<em>nᵉsāḵîm</em>) accompany the burnt and peace offerings, completing the full sacrificial rite. This is the largest sacrificial celebration since Solomon&rsquo;s dedication (2 Chr 7:5).</p>",
    "22": "<p><strong>wayyōḵᵉlû wayyišmtû lip̄nê YHWH bayyôm hahûʾ śimḥāh gᵉḏôlāh</strong> — &lsquo;they ate and drank before the LORD on that day with great joy.&rsquo; The covenantal meal <em>before the LORD</em> echoes Exod 24:11 (the elders saw God and ate and drank). <strong>wayyamliḵû šēnît ʾet-šᵉlōmōh</strong> — &lsquo;they made Solomon king a second time.&rsquo; The first anointing was in 23:1; this second anointing publicly establishes his reign. <strong>wayyimšᵉḥû lᵉṣāḏôq lᵉḵōhēn</strong> — Zadok is anointed as priest, formally establishing the Zadokite priestly line that will continue through the Second Temple period and into the Messianic hopes of Ezekiel (Ezek 40:46; 44:15).</p>",
    "23": "<p><strong>wayyēšeḇ šᵉlōmōh ʿal-kissēʾ YHWH lᵉmeleḵ taḥat dāwid ʾāḇîw</strong> — &lsquo;Solomon sat on the throne of the LORD as king in place of his father David.&rsquo; The phrase <em>kissēʾ YHWH</em> (throne of the LORD) is unique to Chronicles (also 2 Chr 9:8); in Samuel-Kings the throne is called &lsquo;the throne of David.&rsquo; The Chronicler&rsquo;s substitution is theological: the Davidic throne is not a merely human institution but YHWH&rsquo;s own seat of royal administration on earth. <strong>wayyiṣlaḥ</strong> — &lsquo;he prospered&rsquo; — success is stated before any narrative; the Chronicler frames the entire Solomonic era under the sign of divine blessing from the first verse.</p>",
    "24": "<p><strong>wᵉḵol-haggibborîm wᵉḵol-bᵉnê hammelek dāwid nātnû yāḏ taḥat šᵉlōmōh hammelek</strong> — &lsquo;and all the mighty men and all the sons of King David gave their hand under Solomon the king.&rsquo; <em>nātan yāḏ taḥat</em> (to give the hand under) is the idiom for submission/swearing allegiance (2 Chr 30:8; Lam 5:6). The inclusion of David&rsquo;s other sons — who might have been rivals — in the loyal submission is a deliberate contrast with the Absalom rebellion (omitted by Chronicles). Unanimous loyalty marks the transfer of power.</p>",
    "25": "<p><strong>waygaddēl YHWH ʾet-šᵉlōmōh lᵉmaʿlāh lᵉʿênê kol-yiśrāʾēl wayyittēn ʿālāyw hôḏ malḵût</strong> — &lsquo;the LORD magnified Solomon exceedingly in the sight of all Israel and bestowed on him royal majesty.&rsquo; <em>hôḏ malḵût</em> (royal majesty/splendor of kingdom) recalls the divine <em>hôḏ</em> of David&rsquo;s doxology in v. 11. The same divine attribute that belongs to YHWH is bestowed on his king — a participatory theology of kingship. <strong>ʾăšer lōʾ-hāyāh ʿal kol-meleḵ</strong> — &lsquo;such as had not been on any king before him in Israel.&rsquo; Solomon&rsquo;s unprecedented glory is divine gift, not human achievement.</p>",
    "26": "<p>David&rsquo;s reign summary: <strong>wᵉdāwid ben-yišay mālaḵ ʿal-kol-yiśrāʾēl</strong> — &lsquo;Thus David son of Jesse reigned over all Israel.&rsquo; The <em>ben-yišay</em> (son of Jesse) designation is the commoner-origin formula — David was not born into royalty. The arc from Bethlehem shepherd to king over all Israel is the Chronicler&rsquo;s silent witness to divine election.</p>",
    "27": "<p><strong>wᵉhāʿittôt ʾăšer mālaḵ ʿal-yiśrāʾēl ʾarbaʿîm šānāh bᵉḥeḇrôn mālaḵ šeḇaʿ šānîm ûḇîrûšālēm mālaḵ šᵉlōšîm wᵉšāloš šānāh</strong> — &lsquo;the time he reigned over Israel: forty years — seven in Hebron and thirty-three in Jerusalem.&rsquo; The forty-year total is a round number of completeness (like Moses&rsquo; forty years in the wilderness, Israel&rsquo;s forty years of wandering, Saul&rsquo;s reign). The Hebron/Jerusalem division (also 2 Sam 5:5; 1 Kgs 2:11) marks the transition from fugitive-king to temple-city king.</p>",
    "28": "<p><strong>wayyāmot bᵉśêḇāh ṭôḇāh śāḇaʿ yāmîm ʿōšer wᵉḵāḇôḏ</strong> — &lsquo;he died at a good old age, full of days, wealth, and honor.&rsquo; The obituary formula <em>bᵉśêḇāh ṭôḇāh</em> (good old age) is the covenantal blessing formula used for Abraham (Gen 25:8) and Gideon (Judg 8:32). <em>śāḇaʿ yāmîm</em> (full of days) recalls Jacob&rsquo;s death (Gen 35:29, of Isaac). Chronicles gives David the patriarchal death-formula — granting him the honor that Samuel-Kings withholds by recording his failures. <em>ʿōšer wᵉḵāḇôḏ</em> (wealth and honor) are precisely the gifts the Gibeonite-dream Solomon did not ask for (2 Chr 1:11-12) — showing David received in old age what his son was promised at the start.</p>",
    "29": "<p><strong>ûdiḇrê dāwid hammelek hārîʾšōnîm wᵉhāʾaḥărōnîm hinnām kᵉtûḇîm ʿal-diḇrê šᵉmûʾēl hārōʾeh wᵉʿal-diḇrê nātān hannāḇîʾ wᵉʿal-diḇrê gāḏ haḥōzeh</strong> — &lsquo;as for the acts of David, from first to last, they are written in the records of Samuel the seer, the records of Nathan the prophet, and the records of Gad the seer.&rsquo; Three source citations close the Davidic narrative. The triple citation is a literary convention establishing historicity and comprehensive coverage. <em>rōʾeh</em> (seer) and <em>nāḇîʾ</em> (prophet) and <em>ḥōzeh</em> (visionary seer) are three partly synonymous terms for prophetic office. Samuel is always <em>hārōʾeh</em>; Gad is always <em>haḥōzeh</em> in Chronicles.</p>",
    "30": "<p><strong>ʿim kol-malḵûtô ûgᵉḇûrātô wᵉhāʿittôt ʾăšer ʿāḇrû ʿālāyw wᵉʿal-yiśrāʾēl wᵉʿal kol-mamlaḵôt hāʾărāṣôt</strong> — &lsquo;with all the record of his reign and his power, and the times that passed over him and over Israel and over all the kingdoms of the countries.&rsquo; The closing phrase <em>kol-mamlaḵôt hāʾărāṣôt</em> (all the kingdoms of the lands) shows David&rsquo;s reign as having international significance — not just Israel&rsquo;s domestic history. The Chronicler&rsquo;s David is the world-historical king whose dynasty will extend to the nations (cf. Ps 2; 72:11), the preparation for the One whose throne is described in v. 23 as YHWH&rsquo;s own.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '1chronicles')
    merge_comm(existing, CHRON1)
    save_comm('mkt-original', '1chronicles', existing)
    print('1 Chronicles 29 mkt-original written.')

if __name__ == '__main__':
    main()
